def infix_to_postfix(infix_expression):
 operator_stack = []
 output_string = ""

 precedence = {
 '+': 1,
 '-': 1,
 '*': 2,
 '/': 2
 }

 for character in infix_expression:
 if character.isalnum():
 output_string += character
 elif character == '(':n operator_stack.append(character)
 elif character == ')':
 while operator_stack[-1] != '(':n output_string += operator_stack.pop()
 operator_stack.pop()
 else:
 while operator_stack and operator_stack[-1] != '(' and precedence[operator_stack[-1]] >= precedence[character]:
 output_string += operator_stack.pop()
 operator_stack.append(character)

 while operator_stack:
 output_string += operator_stack.pop()

 return output_string

