int evaluate_postfix(char* postfix_expression) {
 int* stack = (int*)malloc(100 * sizeof(int));
 int top = -1;

 for (int i = 0; postfix_expression[i]; i++) {
 if (postfix_expression[i] >= '0' && postfix_expression[i] <= '9') {
 stack[++top] = postfix_expression[i] - '0';
 } else {
 int operand2 = stack[top--];
 int operand1 = stack[top--];
 int result;

 switch (postfix_expression[i]) {
 case '+':
 result = operand1 + operand2;
 break;
 case '-':
 result = operand1 - operand2;
 break;
 case '*':
 result = operand1 * operand2;
 break;
 case '/':
 result = operand1 / operand2;
 break;
 }

 stack[++top] = result;
 }
 }

 return stack[top];
}
